package web

import (
	"os"
	"path/filepath"
	"strings"
	"testing"
)

// readoutJS reads the embedded JS bundle for needle-style contract tests.
// The artifact is generated by esbuild (scripts/build-assets.mjs), which
// normalizes string literals to double quotes; the contract needles in this
// package are written with single quotes. Normalize every double quote back
// to a single quote before matching: the assertions pin wire/behavior
// contracts, not the bundler's quoting style. (Identifiers and selectors are
// unaffected; no needle contains a literal double quote.)
func readoutJS(t *testing.T) string {
	t.Helper()
	src, err := os.ReadFile(filepath.Join("..", "assets", "static", "readout.js"))
	if err != nil {
		t.Fatalf("read readout.js: %v", err)
	}
	return strings.ReplaceAll(string(src), `"`, `'`)
}
